{
  "premium_report": {
    "report_title": "프리미엄 사주 스토리",
    "version": "1.0",
    "sections": [
      {
        "section_id": "section_1",
        "category": "overall",
        "title": "사람과 상황을 바라보는 시선",
        "headline": "관계의 흐름을 읽고 행동의 순서를 다듬는 힘",
        "summary_lines": [
          "관계의 맥락을 세심히 살피는 습관이 당신의 선택에 큰 방향을 잡아줍니다.",
          "사람들과의 거리를 느끼며 말의 순서를 천천히 다듬는 모습이 신뢰를 쌓습니다.",
          "새로운 시작은 작은 순서를 먼저 확인하고 주변 반응을 점검하는 것이 도움이 됩니다."
        ],
        "core_insight": "현재의 흐름은 관계의 맥락을 파악하고 조정하는 능력이 돋보이는 시기입니다. 처음 드러나는 인상보다 실제 판단은 관계의 흐름 속에서 달라지기 쉽고, 가까워질수록 말과 행동의 순서를 차분히 다듬는 편이 신뢰를 쌓는 바탕이 됩니다. 새로운 일을 시작할 때도 작은 순서를 먼저 확인하고 주변의 반응을 살피는 습관이 실질적인 성과를 돕고, 이로 인해 중요한 순간에는 선택의 방향이 보다 명확해집니다.",
        "strength": "관계의 흐름을 파악하고 조율하는 능력이 돋보여 주변 사람들과의 신뢰를 차근차근 쌓아갑니다.",
        "risk": "의도나 상황 파악에 시간이 다소 걸릴 수 있어 의사소통의 타이밍이 어긋나는 순간이 생길 수 있습니다.",
        "action_points": [
          "관계에서 중요한 판단은 한꺼번에 하기보다 일정 기간 동안의 피드백을 모아 결정하세요.",
          "말의 순서를 의식적으로 먼저 점검하는 루틴을 만들어 매일 실천하세요.",
          "다른 사람의 기대와 본인의 가치관 사이에서 균형을 찾되, 필요하면 선을 분명히 하세요."
        ],
        "action_note": "작고 차분한 변화가 관계의 흐름을 더 매끄럽게 만들 수 있습니다."
      }
    ]
  }
}
